{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import org.junit.jupiter.api.Test

class BinaryExpressionWrappingRuleElvisTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Issue 2143 - Endless loop in wrapping binary expression after elvis operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                               $EOL_CHAR
            val foo =
                bar
                    ?:
                    throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        // The issue is that it should NOT merge the last two lines if it results in exceeding max line length
        // or something that causes an endless loop.
        // Actually, the issue description says: "As a line may not end with ?: ktlint merges the last two lines. This however results in wrapping the line again to the original situation. As of that an endless loop results."

        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .isFormattedAs(code)
    }
}
