235→    if (this is LeafElement) {
236→        if (this.elementType == WHITE_SPACE) {
237→            return replaceWhitespaceWith(text)
238→        }
239→        val previous = treePrev ?: prevLeaf()
240→        if (previous != null && previous.elementType == WHITE_SPACE) {
241→            previous.replaceWhitespaceWith(text)
242→        } else {
243→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
244→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
245→            }
246→        }
247→    } else {
248→        when (val prevSibling = prevSibling()) {
249→            null -> {
250→                // Never insert a whitespace element as first child node in a composite node. Instead, upsert just before the composite node
251→                treeParent.upsertWhitespaceBeforeMe(text)
252→            }
253→
254→            is LeafElement -> {
255→                prevSibling.upsertWhitespaceAfterMe(text)
256→            }
257→
258→            else -> {
259→                // Insert in between two composite nodes
260→                PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
