import org.junit.jupiter.api.Test

class BinaryExpressionWrappingRuleElvisTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Issue 2143 - Given a binary expression with elvis operator at the start of the line which exceeds the max line length, then do not wrap after the elvis operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER             $EOL_CHAR
            val foo =
                bar
                    ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        // Line 4 (?: ...) is 9 + 2 + 1 + 5 + 1 + 33 = 51 chars, which exceeds 25.
        // It should report a violation but not autocorrect it, to avoid endless loop with ChainWrappingRule
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolationWithoutAutoCorrect(4, 9, "Line is exceeding max line length")
    }
}
